// src/components/admin/LinkHome.jsx
import React, { useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign"; // adjust path

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [editingId, setEditingId] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    if (editingId) {
      setLinks(links.map((l) => (l.id === editingId ? { ...l, name } : l)));
      setEditingId(null);
    } else {
      setLinks([...links, { id: Date.now(), name }]);
    }
    setName("");
  };

  const startEdit = (link) => {
    setName(link.name);
    setEditingId(link.id);
  };

  const removeLink = (id) => {
    setLinks(links.filter((l) => l.id !== id));
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        {/* Header */}
        <div className={design.headerWrapper}>
          <div>
            <h1 className={design.title}>Navigation Links</h1>
            <p className={design.subtitle}>
              Manage main navigation links shown on the public website.
            </p>
          </div>
        </div>

        {/* Main Card */}
        <div className={design.card}>
          {/* Form */}
          <div className={design.formSection}>
            <form onSubmit={handleSubmit} className={design.form}>
              <input
                type="text"
                placeholder="Enter link name (e.g. Home, About, Services...)"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className={design.input}
                autoFocus
              />

              <motion.button
                whileTap={{ scale: 0.97 }}
                type="submit"
                className={design.buttonPrimary}
              >
                <Plus size={18} />
                {editingId ? "Update Link" : "Add Link"}
              </motion.button>
            </form>
          </div>

          {/* List */}
          <div className={design.listWrapper}>
            {/* Desktop header */}
            <div className={design.tableHeader}>
              <div>Name</div>
              <div className="text-right pr-2">Actions</div>
            </div>

            <AnimatePresence mode="popLayout">
              {links.length === 0 ? (
                <div className={design.emptyState}>
                  No navigation links created yet.
                </div>
              ) : (
                links.map((link) => (
                  <motion.div
                    key={link.id}
                    initial="hidden"
                    animate="visible"
                    exit="exit"
                    variants={design.itemVariants}
                    transition={{ duration: 0.22 }}
                    layout
                    className={design.row}
                  >
                    {/* Name + badge + mobile actions */}
                    <div className={design.mobileNameArea}>
                      <div className={design.nameAndBadge}>
                        <span className={design.nameText}>{link.name}</span>
                        <span className={design.badge}>Active</span>
                      </div>

                      {/* Mobile actions */}
                      <div className={design.actionsMobile}>
                        <button
                          onClick={() => startEdit(link)}
                          className={design.actionButton}
                          title="Edit"
                        >
                          <Pencil size={18} />
                        </button>
                        <button
                          onClick={() => removeLink(link.id)}
                          className={design.actionButton}
                          title="Delete"
                        >
                          <Trash2 size={18} className="text-red-500/80" />
                        </button>
                      </div>
                    </div>

                    {/* Desktop actions */}
                    <div className={design.actionsDesktop}>
                      <button
                        onClick={() => startEdit(link)}
                        className={design.actionButton}
                        title="Edit link"
                      >
                        <Pencil size={18} />
                      </button>
                      <button
                        onClick={() => removeLink(link.id)}
                        className={design.actionButton}
                        title="Delete link"
                      >
                        <Trash2 size={18} className="text-red-500/80" />
                      </button>
                    </div>
                  </motion.div>
                ))
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
